     1→import { execFile } from 'node:child_process';
     2→import { promisify } from 'node:util';
     3→import { join } from 'node:path';
     4→import { existsSync } from 'node:fs';
     5→
     6→const exec = promisify(execFile);
     7→
     8→const WORKTREE_DIR = '.jiranimo-worktrees';
     9→
    10→async function git(args: string[], cwd: string): Promise<string> {
    11→  const { stdout } = await exec('git', args, { cwd });
    12→  return stdout.trim();
    13→}
    14→
    15→/**
    16→ * Check if a ref (branch, remote ref, etc.) exists.
    17→ */
    18→async function refExists(repoPath: string, ref: string): Promise<boolean> {
    19→  return git(['rev-parse', '--verify', ref], repoPath)
    20→    .then(() => true)
    21→    .catch(() => false);
    22→}
    23→
    24→/**
    25→ * Resolve the best start point for a new branch.
    26→ * Tries in order: remote/baseBranch, local baseBranch, HEAD.
    27→ */
    28→async function resolveStartPoint(
    29→  repoPath: string,
    30→  baseBranch: string,
    31→  remote: string | undefined,
    32→  hasRemote: boolean,
    33→): Promise<string> {
    34→  if (hasRemote && remote) {
    35→    const remoteRef = `${remote}/${baseBranch}`;
    36→    if (await refExists(repoPath, remoteRef)) return remoteRef;
    37→  }
    38→  if (await refExists(repoPath, baseBranch)) return baseBranch;
    39→  // Last resort: use whatever HEAD points to
    40→  return 'HEAD';
    41→}
    42→
    43→/**
    44→ * Create a git worktree for a task.
    45→ * Returns the absolute path to the worktree directory.
    46→ *
    47→ * If the branch already exists (e.g. re-implementing a ticket),
    48→ * the worktree is created from the existing branch instead of making a new one.
    49→ */
    50→export async function createWorktree(
    51→  repoPath: string,
    52→  taskKey: string,
    53→  branchName: string,
    54→  baseBranch: string,
    55→  remote?: string,
    56→): Promise<string> {
    57→  const worktreePath = join(repoPath, WORKTREE_DIR, taskKey);
    58→
    59→  // Clean up stale worktree if it exists from a previous crash
    60→  if (existsSync(worktreePath)) {
    61→    await removeWorktree(repoPath, worktreePath).catch(() => {});
    62→  }
    63→
    64→  // Fetch latest from remote if available
    65→  const hasRemote = await git(['remote'], repoPath).then(r => r.length > 0).catch(() => false);
    66→  if (hasRemote && remote) {
    67→    await git(['fetch', remote], repoPath).catch(() => {});
    68→  }
    69→
    70→  // If the branch already exists, reuse it; otherwise create a new one
    71→  if (await refExists(repoPath, branchName)) {
    72→    await git(['worktree', 'add', worktreePath, branchName], repoPath);
    73→    // Pull latest changes so we start from an up-to-date branch
    74→    if (hasRemote && remote) {
    75→      await git(['pull', remote, branchName], worktreePath).catch(() => {});
    76→    }
    77→  } else {
    78→    const startPoint = await resolveStartPoint(repoPath, baseBranch, remote, hasRemote);
    79→    await git(['worktree', 'add', worktreePath, '-b', branchName, startPoint], repoPath);
    80→  }
    81→
    82→  return worktreePath;
    83→}
    84→
    85→/**
    86→ * Remove a worktree and its branch.
    87→ */
    88→export async function removeWorktree(repoPath: string, worktreePath: string): Promise<void> {
    89→  try {
    90→    await git(['worktree', 'remove', worktreePath, '--force'], repoPath);
    91→  } catch {
    92→    // If remove fails, try pruning
    93→    await git(['worktree', 'prune'], repoPath).catch(() => {});
    94→  }
    95→}
    96→
    97→/**
    98→ * Clean up stale worktree entries (e.g., after crashes).
    99→ * Call on server startup.
   100→ */
   101→export async function pruneWorktrees(repoPath: string): Promise<void> {
   102→  await git(['worktree', 'prune'], repoPath).catch(() => {});
   103→}
   104→
   105→/**
   106→ * Find the first git repository inside a directory.
   107→ * A directory is a git repo if it contains a `.git` directory (not just being inside one).
   108→ */
   109→export async function findGitRepo(rootPath: string): Promise<string | null> {
   110→  // Check if rootPath itself has a .git directory
   111→  if (existsSync(join(rootPath, '.git'))) {
   112→    return rootPath;
   113→  }
   114→
   115→  // Scan subdirectories for a .git directory
   116→  const { readdirSync } = await import('node:fs');
   117→  for (const entry of readdirSync(rootPath, { withFileTypes: true })) {
   118→    if (!entry.isDirectory() || entry.name.startsWith('.')) continue;
   119→    const subPath = join(rootPath, entry.name);
   120→    if (existsSync(join(subPath, '.git'))) {
   121→      return subPath;
   122→    }
   123→  }
   124→
   125→  return null;
   126→}
