    16→export function branchName(prefix: string, issueKey: string, summary: string): string {
    17→  const slug = slugify(summary);
    18→  const rid = Math.random().toString(36).substring(2, 5);
    19→  return `${prefix}${issueKey}-${slug}-${rid}`;
    20→}
