    22→export function commitType(issueType: string): string {
    23→  const lower = issueType.toLowerCase();
    24→  if (lower === 'bug') return 'fix';
    25→  if (lower === 'story' || lower === 'feature') return 'feat';
    26→  return 'chore';
    27→}
