    44→export async function setupBranch(
    45→  cwd: string,
    46→  issueKey: string,
    47→  summary: string,
    48→  config: GitConfig,
    49→  baseBranchOverride?: string,
    50→): Promise<string> {
    51→  const base = baseBranchOverride ?? config.defaultBaseBranch;
    52→  const branch = branchName(config.branchPrefix, issueKey, summary);
    53→
    54→  // Try to fetch from remote — skip gracefully if no remote exists
    55→  const hasRemote = await git(['remote'], cwd).then(r => r.length > 0).catch(() => false);
    56→  if (hasRemote) {
    57→    await git(['fetch', config.pushRemote], cwd);
    58→  }
    59→
    60→  await git(['checkout', base], cwd);
    61→
    62→  if (hasRemote) {
    63→    await git(['pull', config.pushRemote, base], cwd).catch(() => {
    64→      // Pull may fail if remote branch doesn't exist yet — that's ok
    65→    });
    66→  }
    67→
    68→  await git(['checkout', '-b', branch], cwd);
    69→
    70→  return branch;
    71→}
